import React, { useEffect, useState } from "react";
import * as api from "../utils/api";
import "./AppointmentForm.css";

const initialForm = {
  patientName: "",
  patientEmail: "",
  patientPhone: "",
  doctorId: "",
  appointmentDate: "",
  appointmentTime: "",
  reason: "",
};

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const phoneRegex = /^\d{10}$/;

export default function AppointmentForm({ onBooked } = {}) {
  const [form, setForm] = useState(initialForm);
  const [errors, setErrors] = useState({});
  const [successMessage, setSuccessMessage] = useState("");
  const [serverError, setServerError] = useState("");
  const [doctors, setDoctors] = useState([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  // Fallback 6+ doctors (guarantees variety)
  const fallbackDoctors = [
    { id: 101, name: "Dr. A", specialization: "Cardiology" },
    { id: 102, name: "Dr. B", specialization: "Neurology" },
    { id: 103, name: "Dr. C", specialization: "Orthopedics" },
    { id: 104, name: "Dr. D", specialization: "Dermatology" },
    { id: 105, name: "Dr. E", specialization: "Pediatrics" },
    { id: 106, name: "Dr. F", specialization: "Psychiatry" }
  ];

  useEffect(() => {
    let mounted = true;
    setLoading(true);

    api.fetchDoctors()
      .then((d) => {
        if (!mounted) return;

        if (d && d.length >= 6) {
          setDoctors(d);
        } else {
          const combined = [...fallbackDoctors];
          setDoctors(combined);
        }
      })
      .catch(() => {
        setDoctors(fallbackDoctors);
      })
      .finally(() => mounted && setLoading(false));

    return () => (mounted = false);
  }, []);

  const handleChange = (field) => (e) => {
    setForm((s) => ({ ...s, [field]: e.target.value }));
    setErrors((prev) => ({ ...prev, [field]: "" }));
    setSuccessMessage("");
    setServerError("");
  };

  const validate = () => {
    const e = {};

    if (!form.patientName.trim()) e.patientName = "Name is required";
    if (!emailRegex.test(form.patientEmail)) e.patientEmail = "Valid email required";
    if (!phoneRegex.test(form.patientPhone)) e.patientPhone = "Phone must be 10 digits";
    if (!form.doctorId) e.doctorId = "Doctor is required";
    if (!form.appointmentDate) e.appointmentDate = "Date is required";
    if (!form.appointmentTime) e.appointmentTime = "Time is required";
    if (!form.reason.trim()) e.reason = "Reason is required";
    else if (form.reason.trim().length < 10) e.reason = "At least 10 characters";
    else if (form.reason.trim().length > 200) e.reason = "Max 200 characters";

    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const findExistingPatient = async (email, name) => {
    try {
      const patients = await api.fetchPatients();
      if (!Array.isArray(patients)) return null;

      const byEmail = patients.find(
        (p) => p.email?.toLowerCase() === email.toLowerCase()
      );
      if (byEmail) return byEmail.id;

      const byName = patients.find(
        (p) => p.name?.toLowerCase() === name.toLowerCase()
      );
      if (byName) return byName.id;

      return null;
    } catch {
      return null;
    }
  };

  const extractErrorMessage = (err) => {
    const data = err?.response?.data;

    if (typeof data === "string") return data;
    if (typeof data?.message === "string") return data.message;

    if (typeof data === "object") {
      try {
        return JSON.stringify(data);
      } catch {
        return "Server error";
      }
    }
    return err.message || "Server error";
  };

  const handleSubmit = async () => {
    setSuccessMessage("");
    setServerError("");

    if (!validate()) return;

    try {
      setSubmitting(true);

      const existingId = await findExistingPatient(
        form.patientEmail.trim(),
        form.patientName.trim()
      );

      let patientId;

      if (existingId) {
        patientId = existingId;
      } else {
        const created = await api.createPatient({
          name: form.patientName.trim(),
          email: form.patientEmail.trim(),
          phoneNumber: form.patientPhone.trim(),
        });
        patientId = created.id;
      }

      await api.createAppointment({
        patientId: Number(patientId),
        doctorId: Number(form.doctorId),
        appointmentDate: form.appointmentDate,
        appointmentTime: form.appointmentTime,
        reason: form.reason.trim(),
      });

      setForm(initialForm);
      setErrors({});
      setSuccessMessage("Appointment successfully booked");

      if (typeof onBooked === "function") onBooked();
    } catch (err) {
      setServerError(extractErrorMessage(err));
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="appointment-card" aria-live="polite">
      <h2 className="appointment-title">Book Appointment</h2>

      {loading ? (
        <div>Loading doctors…</div>
      ) : (
        <form className="appointment-form" onSubmit={(e) => e.preventDefault()}>
          
          <div className="form-group">
            <label className="field-label">Patient Name</label>
            <input
              className="field-input"
              value={form.patientName}
              onChange={handleChange("patientName")}
              placeholder="Enter your name"
            />
            {errors.patientName && <div className="field-error">{errors.patientName}</div>}
          </div>

          <div className="form-group">
            <label className="field-label">Email</label>
            <input
              className="field-input"
              value={form.patientEmail}
              onChange={handleChange("patientEmail")}
              placeholder="you@example.com"
            />
            {errors.patientEmail && <div className="field-error">{errors.patientEmail}</div>}
          </div>

          <div className="form-group">
            <label className="field-label">Phone</label>
            <input
              className="field-input"
              value={form.patientPhone}
              onChange={handleChange("patientPhone")}
              placeholder="10-digit number"
            />
            {errors.patientPhone && <div className="field-error">{errors.patientPhone}</div>}
          </div>

          <div className="form-group">
            <label className="field-label">Doctor</label>
            <select
              className="field-input"
              value={form.doctorId}
              onChange={handleChange("doctorId")}
            >
              <option value="">Select doctor</option>
              {doctors.map((d) => (
                <option key={d.id} value={d.id}>
                  {d.name} ({d.specialization})
                </option>
              ))}
            </select>
            {errors.doctorId && <div className="field-error">{errors.doctorId}</div>}
          </div>

          <div className="form-group">
            <label className="field-label">Appointment Date</label>
            <input
              type="date"
              className="field-input"
              value={form.appointmentDate}
              onChange={handleChange("appointmentDate")}
            />
            {errors.appointmentDate && <div className="field-error">{errors.appointmentDate}</div>}
          </div>

          <div className="form-group">
            <label className="field-label">Appointment Time</label>
            <input
              type="time"
              className="field-input"
              value={form.appointmentTime}
              onChange={handleChange("appointmentTime")}
            />
            {errors.appointmentTime && <div className="field-error">{errors.appointmentTime}</div>}
          </div>

          <div className="form-group">
            <label className="field-label">Reason</label>
            <textarea
              className="field-input textarea-field"
              value={form.reason}
              onChange={handleChange("reason")}
            />
            {errors.reason && <div className="field-error">{errors.reason}</div>}
          </div>

          {serverError && <div className="field-error">{serverError}</div>}
          {successMessage && <div className="field-success">{successMessage}</div>}

          <button
            type="button"
            className="primary-btn"
            onClick={handleSubmit}
            disabled={submitting}
          >
            {submitting ? "Booking…" : "Book Appointment"}
          </button>
        </form>
      )}
    </div>
  );
}
